import { useState, useRef, useEffect } from 'react';
import { Bell, Check } from 'lucide-react';
import { useNotificationStore } from '@/store/notificationStore';
import { useNavigate } from 'react-router-dom';
import type { INotification } from '@/types/notification.types';

export const NotificationBell = () => {
    const {
        notifications,
        unreadCount,
        fetchNotifications,
        fetchUnreadCount,
        markAsRead,
        markAllAsRead,
        clearAll,
        isLoading,
        filter,
        setFilter
    } = useNotificationStore();
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);
    const navigate = useNavigate();

    // Initial fetch
    useEffect(() => {
        fetchUnreadCount();
    }, []);

    const handleToggle = () => {
        if (!isOpen) {
            fetchNotifications();
        }
        setIsOpen(!isOpen);
    };

    const handleClickOutside = (event: MouseEvent) => {
        if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
            setIsOpen(false);
        }
    };

    useEffect(() => {
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleNotificationClick = async (notification: INotification) => {
        if (!notification.isRead) {
            await markAsRead(notification._id);
        }

        if (notification.type === 'SESSION_STARTED' && notification.workshopId) {
            if (notification.recipientRole === 'chef') {
                navigate(`/chef/workshops/${notification.workshopId}`); // Or live session
            } else {
                navigate(`/foodie/live-session/${notification.workshopId}`);
            }
        } else if ((notification.type === 'WORKSHOP_APPROVED' || notification.type === 'WORKSHOP_REJECTED') && notification.workshopId) {
            navigate(`/chef/workshops`);
        }
    };

    return (
        <div className="relative" ref={dropdownRef}>
            <button
                onClick={handleToggle}
                className="relative p-2 rounded-full hover:bg-gray-100 transition-colors focus:outline-none"
            >
                <Bell size={24} className="text-gray-600" />
                {unreadCount > 0 && (
                    <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-red-100 transform translate-x-1/4 -translate-y-1/4 bg-red-600 rounded-full">
                        {unreadCount > 99 ? '99+' : unreadCount}
                    </span>
                )}
            </button>

            {isOpen && (
                <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-2xl overflow-hidden z-[100] border border-gray-100 animate-in fade-in zoom-in-95 duration-200 origin-top-right">
                    <div className="p-4 border-b border-gray-100 bg-gray-50/50 backdrop-blur-sm">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="font-semibold text-gray-800">Notifications</h3>
                            <button
                                onClick={handleToggle}
                                className="text-gray-400 hover:text-gray-600"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                            </button>
                        </div>

                        <div className="flex gap-2 mb-2">
                            <button
                                onClick={() => setFilter('all')}
                                className={`px-3 py-1 text-xs font-medium rounded-full transition-colors ${filter === 'all' ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
                            >
                                All
                            </button>
                            <button
                                onClick={() => setFilter('unread')}
                                className={`px-3 py-1 text-xs font-medium rounded-full transition-colors ${filter === 'unread' ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
                            >
                                Unread
                            </button>
                            <button
                                onClick={() => setFilter('read')}
                                className={`px-3 py-1 text-xs font-medium rounded-full transition-colors ${filter === 'read' ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
                            >
                                Read
                            </button>
                        </div>

                        <div className="flex justify-between items-center mt-2">
                            {unreadCount > 0 && (
                                <button
                                    onClick={markAllAsRead}
                                    className="text-xs text-indigo-600 hover:text-indigo-800 font-medium hover:underline flex items-center gap-1"
                                >
                                    <Check size={12} /> Mark all read
                                </button>
                            )}
                            {notifications.length > 0 && (
                                <button
                                    onClick={clearAll}
                                    className="text-xs text-red-600 hover:text-red-800 font-medium hover:underline ml-auto"
                                >
                                    {filter === 'all' ? 'Clear all' : `Clear all ${filter}`}
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="max-h-96 overflow-y-auto">
                        {isLoading ? (
                            <div className="p-8 text-center text-gray-400 flex flex-col items-center gap-2">
                                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                            </div>
                        ) : notifications.length === 0 ? (
                            <div className="p-8 text-center text-gray-400 flex flex-col items-center gap-2">
                                <Bell size={32} className="opacity-20" />
                                <p className="text-sm">No notifications found</p>
                            </div>
                        ) : (
                            <div className="divide-y divide-gray-50">
                                {notifications.map((notification) => (
                                    <div
                                        key={notification._id}
                                        onClick={() => handleNotificationClick(notification)}
                                        className={`p-4 hover:bg-gray-50 transition-colors cursor-pointer relative group ${!notification.isRead ? 'bg-indigo-50/30' : ''}`}
                                    >
                                        {!notification.isRead && (
                                            <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-500"></div>
                                        )}
                                        <div className="flex gap-3">
                                            <div className={`mt-1 h-2 w-2 rounded-full flex-shrink-0 ${!notification.isRead ? 'bg-indigo-500' : 'bg-transparent'}`}></div>
                                            <div className="flex-1">
                                                <p className={`text-sm ${!notification.isRead ? 'font-semibold text-gray-900' : 'text-gray-600'}`}>
                                                    {notification.title}
                                                </p>
                                                <p className="text-xs text-gray-500 mt-1 line-clamp-2">
                                                    {notification.message}
                                                </p>
                                                <p className="text-[10px] text-gray-400 mt-2">
                                                    {new Date(notification.createdAt).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: 'numeric', hour12: true })}
                                                </p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

import { useOtp } from '@/hooks/auth/useOtp';
import { motion } from "framer-motion";
import { KeyRound, ArrowRight, ArrowLeft } from "lucide-react";
import logo from "../../../assets/logo.png";

export default function Otp() {
  const {
    otp,
    inputRefs,
    handleChange,
    handleKeyDown,
    handleLogIn,
    handleVerify,
    handleResendOtp,
    otpError,
    timer
  } = useOtp();

  return (
    <div className="min-h-screen bg-neutral-50 flex flex-col items-center justify-center font-sans overflow-hidden relative py-12">
      {/* Background abstract elements */}
      <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1 }}
          className="fixed top-0 right-0 w-[600px] h-[600px] bg-emerald-100/40 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/3 pointer-events-none"
      />
      <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1 }}
          className="fixed bottom-0 left-0 w-[500px] h-[500px] bg-teal-50/50 rounded-full blur-[80px] translate-y-1/3 -translate-x-1/3 pointer-events-none"
      />

      {/* Navbar Minimal */}
      <div className="fixed top-0 w-full p-6 lg:px-8 flex justify-between items-center z-50">
          <div onClick={handleLogIn} className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity">
              <img src={logo} alt="Dishcovery" className="h-10 w-auto object-contain" />
          </div>
          <button
              onClick={handleLogIn}
              className="px-6 py-2 bg-white/80 backdrop-blur-sm border border-emerald-100 text-emerald-800 font-semibold rounded-full hover:bg-emerald-50 hover:shadow-md transition-all flex items-center gap-2">
              <ArrowLeft className="w-4 h-4" /> Back to Login
          </button>
      </div>

      <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          transition={{ duration: 0.5, type: "spring", stiffness: 100 }}
          className="relative z-10 w-full max-w-md bg-white/80 backdrop-blur-xl shadow-2xl rounded-3xl p-8 sm:p-10 border border-white mt-8"
      >
          <div className="flex flex-col items-center mb-8">
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.2 }} className="text-center">
                  <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-4">
                      <KeyRound className="w-8 h-8 text-emerald-600" />
                  </div>
                  <h1 className="text-3xl font-extrabold text-neutral-900 tracking-tight">Verify Email</h1>
                  <p className="text-neutral-500 mt-2 text-sm max-w-xs mx-auto">
                      Please enter the 4-digit code sent to your email address.
                  </p>
              </motion.div>
          </div>

          <div className="space-y-6">
              <motion.div 
                initial={{ y: 20, opacity: 0 }} 
                animate={{ y: 0, opacity: 1 }} 
                transition={{ delay: 0.3 }}
                className="flex justify-center gap-4 mb-4"
              >
                  {otp.map((digit, index) => (
                      <motion.input
                          initial={{ opacity: 0, y: 20 }}
                          animate={{ opacity: 1, y: 0 }}
                          transition={{ delay: 0.3 + index * 0.1 }}
                          key={index}
                          ref={inputRefs[index] as any}
                          type="text"
                          inputMode="numeric"
                          maxLength={1}
                          value={digit}
                          onChange={(e) => handleChange(index, e.target.value)}
                          onKeyDown={(e) => handleKeyDown(index, e as any)}
                          className={`w-14 h-16 sm:w-16 sm:h-20 text-center text-3xl font-bold bg-neutral-50 border-2 rounded-2xl outline-none transition-all duration-200 shadow-sm
                          ${otpError ? 'border-red-400 focus:border-red-500 focus:ring-4 focus:ring-red-100 text-red-600' : 'border-neutral-200 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-100 text-neutral-800'}`}
                      />
                  ))}
              </motion.div>

              <motion.div initial={{ y: 20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.6 }} className="pt-2">
                  <button
                      onClick={handleVerify as any}
                      className="w-full relative group flex items-center justify-center gap-3 py-4 bg-gradient-to-r from-emerald-600 to-green-500 text-white font-bold text-lg rounded-2xl hover:scale-[1.02] transition-all duration-300 shadow-lg shadow-emerald-500/30 hover:shadow-emerald-500/50"
                  >
                      <span>Verify Code</span>
                      <ArrowRight className="h-5 w-5 group-hover:translate-x-1 transition-transform" />
                  </button>
              </motion.div>

              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.7 }} className="text-center pt-2">
                  {timer > 0 ? (
                      <p className="text-sm font-medium text-neutral-500">
                          Resend code in <span className="text-emerald-600 font-bold">{timer}s</span>
                      </p>
                  ) : (
                      <p className="text-sm font-medium text-neutral-600">
                          Didn't receive the code?{' '}
                          <button onClick={handleResendOtp as any} className="text-emerald-600 hover:text-emerald-700 hover:underline font-semibold transition-colors">
                              Resend OTP
                          </button>
                      </p>
                  )}
              </motion.div>
          </div>
      </motion.div>
    </div>
  );
}

import { useState } from 'react';
import { useSignup } from "@/hooks/auth/useSignup";
import { GoogleLogin } from '@react-oauth/google';
import { useNavigate } from "react-router-dom";
import { motion } from 'framer-motion';
import { User, Mail, Lock, Eye, EyeOff, Shield, ArrowRight } from 'lucide-react';
import logo from '../../../assets/logo.png';

export default function Signup() {
  const navigate = useNavigate();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const {
    agreedToTerms,
    formData,
    handleBackToLogin,
    handleGoogleSuccess,
    handleInputChange,
    handleSignUp,
    setAgreedToTerms,
    errors,
  } = useSignup();

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSignUp(e as any);
    }
  };

  return (
    <div className="min-h-screen bg-neutral-50 flex flex-col items-center justify-center font-sans overflow-hidden relative py-12">

      {/* Background abstract elements */}
      <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1 }}
          className="fixed top-0 right-0 w-[600px] h-[600px] bg-emerald-100/40 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/3 pointer-events-none"
      />
      <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1 }}
          className="fixed bottom-0 left-0 w-[500px] h-[500px] bg-teal-50/50 rounded-full blur-[80px] translate-y-1/3 -translate-x-1/3 pointer-events-none"
      />

      {/* Navbar Minimal */}
      <div className="fixed top-0 w-full p-6 lg:px-8 flex justify-between items-center z-50">
          <div
            onClick={() => navigate('/foodie/dashboard')}
            className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity"
          >
            <img
              src={logo}
              alt="Dishcovery"
              className="h-10 w-auto object-contain"
            />
          </div>
          <button
            onClick={handleBackToLogin}
            className="px-6 py-2 bg-white/80 backdrop-blur-sm border border-emerald-100 text-emerald-800 font-semibold rounded-full hover:bg-emerald-50 hover:shadow-md transition-all">
            Login
          </button>
      </div>

      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        transition={{ duration: 0.5, type: "spring", stiffness: 100 }}
        className="relative z-10 w-full max-w-lg bg-white/80 backdrop-blur-xl shadow-2xl rounded-3xl p-8 sm:p-10 border border-white mt-8"
      >
        <div className="flex flex-col items-center mb-6">
          <motion.div
             initial={{ opacity: 0 }}
             animate={{ opacity: 1 }}
             transition={{ delay: 0.2 }}
             className="text-center"
          >
            <h1 className="text-3xl font-extrabold text-neutral-900 tracking-tight">
              Create an Account
            </h1>
            <p className="text-neutral-500 mt-2 text-sm">
              Discover, cook, and share amazing recipes
            </p>
          </motion.div>
        </div>

        <div className="space-y-4">

          {/* Name */}
          <motion.div 
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            <label className="block mb-1.5 text-sm font-semibold text-neutral-700">Full Name</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <User className={`h-5 w-5 ${errors.name ? 'text-red-400' : 'text-neutral-400 group-focus-within:text-emerald-500'} transition-colors duration-200`} />
              </div>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                placeholder="John Doe"
                className={`w-full pl-12 pr-4 py-3 bg-neutral-50 border ${errors.name ? 'border-red-300 ring-red-100' : 'border-neutral-200 focus:border-emerald-500 focus:ring-emerald-100'} rounded-xl outline-none focus:ring-4 transition-all duration-200 text-neutral-800 placeholder-neutral-400 font-medium`}
              />
            </div>
            {errors.name && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs mt-1 ml-1 font-medium">{errors.name}</motion.p>
            )}
          </motion.div>

          {/* Email */}
          <motion.div 
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.35 }}
          >
            <label className="block mb-1.5 text-sm font-semibold text-neutral-700">Email Address</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Mail className={`h-5 w-5 ${errors.email ? 'text-red-400' : 'text-neutral-400 group-focus-within:text-emerald-500'} transition-colors duration-200`} />
              </div>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                placeholder="john@dishcovery.com"
                className={`w-full pl-12 pr-4 py-3 bg-neutral-50 border ${errors.email ? 'border-red-300 ring-red-100' : 'border-neutral-200 focus:border-emerald-500 focus:ring-emerald-100'} rounded-xl outline-none focus:ring-4 transition-all duration-200 text-neutral-800 placeholder-neutral-400 font-medium`}
              />
            </div>
            {errors.email && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs mt-1 ml-1 font-medium">{errors.email}</motion.p>
            )}
          </motion.div>

          {/* Password */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.4 }}
          >
            <label className="block mb-1.5 text-sm font-semibold text-neutral-700">Password</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Lock className={`h-5 w-5 ${errors.password ? 'text-red-400' : 'text-neutral-400 group-focus-within:text-emerald-500'} transition-colors duration-200`} />
              </div>
              <input
                type={showPassword ? "text" : "password"}
                name="password"
                value={formData.password}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                placeholder="••••••••"
                className={`w-full pl-12 pr-12 py-3 bg-neutral-50 border ${errors.password ? 'border-red-300 ring-red-100' : 'border-neutral-200 focus:border-emerald-500 focus:ring-emerald-100'} rounded-xl outline-none focus:ring-4 transition-all duration-200 text-neutral-800 placeholder-neutral-400 font-medium tracking-wider`}
              />
              <button
                type="button"
                className="absolute inset-y-0 right-0 pr-4 flex items-center text-neutral-400 hover:text-emerald-500 transition-colors"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
              </button>
            </div>
            {errors.password && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs mt-1 ml-1 font-medium">{errors.password}</motion.p>
            )}
          </motion.div>

          {/* Confirm Password */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.45 }}
          >
            <label className="block mb-1.5 text-sm font-semibold text-neutral-700">Confirm Password</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Shield className={`h-5 w-5 ${errors.confirmPassword ? 'text-red-400' : 'text-neutral-400 group-focus-within:text-emerald-500'} transition-colors duration-200`} />
              </div>
              <input
                type={showConfirmPassword ? "text" : "password"}
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                placeholder="••••••••"
                className={`w-full pl-12 pr-12 py-3 bg-neutral-50 border ${errors.confirmPassword ? 'border-red-300 ring-red-100' : 'border-neutral-200 focus:border-emerald-500 focus:ring-emerald-100'} rounded-xl outline-none focus:ring-4 transition-all duration-200 text-neutral-800 placeholder-neutral-400 font-medium tracking-wider`}
              />
              <button
                type="button"
                className="absolute inset-y-0 right-0 pr-4 flex items-center text-neutral-400 hover:text-emerald-500 transition-colors"
                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
              >
                {showConfirmPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
              </button>
            </div>
            {errors.confirmPassword && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs mt-1 ml-1 font-medium">{errors.confirmPassword}</motion.p>
            )}
          </motion.div>

          {/* Role Dropdown */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.5 }}
          >
            <label className="block mb-1.5 text-sm font-semibold text-neutral-700">Select Role</label>
            <select
              name="role"
              value={formData.role}
              onChange={handleInputChange}
              className={`w-full px-4 py-3 bg-neutral-50 border ${errors.role ? 'border-red-300 ring-red-100' : 'border-neutral-200 focus:border-emerald-500 focus:ring-emerald-100'} rounded-xl outline-none focus:ring-4 transition-all duration-200 text-neutral-800 font-medium`}
            >
              <option value="">Select your role</option>
              <option value="user">Foodie (User)</option>
              <option value="chef">Chef</option>
            </select>
            {errors.role && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs mt-1 ml-1 font-medium">{errors.role}</motion.p>
            )}
          </motion.div>

          {/* Terms Checkbox */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ delay: 0.55 }}
            className="flex items-start gap-2 pt-2"
          >
            <div className="flex items-center h-5">
              <input
                type="checkbox"
                id="terms"
                checked={agreedToTerms}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setAgreedToTerms(e.target.checked)}
                className="w-4 h-4 text-emerald-500 bg-neutral-100 border-neutral-300 rounded focus:ring-emerald-500 cursor-pointer"
              />
            </div>
            <label htmlFor="terms" className="text-sm text-neutral-600 leading-tight">
              I agree to the <span className="text-emerald-600 hover:underline cursor-pointer">Terms of Service</span> and <span className="text-emerald-600 hover:underline cursor-pointer">Privacy Policy</span>
            </label>
          </motion.div>
          {errors.terms && (
              <motion.p initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-red-500 text-xs ml-6 font-medium">{errors.terms}</motion.p>
          )}

          {/* Buttons */}
          <motion.div
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.6 }}
            className="pt-2 flex flex-col gap-3"
          >
            <button
              onClick={handleSignUp}
              className="w-full relative group flex items-center justify-center gap-3 py-3.5 bg-gradient-to-r from-emerald-600 to-green-500 text-white font-bold text-lg rounded-xl hover:scale-[1.02] transition-all duration-300 shadow-lg shadow-emerald-500/30 hover:shadow-emerald-500/50"
            >
              <span>Create Account</span>
